<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('products.manage');$id=(int)vp3_input('id');if(vp3_method()==='POST'){vp3_verify_csrf();$fields=['hosting_type'=>['self_hosted','vp3_hosted','enterprise'],'billing_type'=>['one_time','subscription','custom'],'billing_interval'=>['none','monthly','yearly','custom'],'status'=>['draft','active','retired']];foreach($fields as $key=>$allowed)if(!in_array(vp3_input($key),$allowed,true))exit('Invalid plan value.');$values=[(int)vp3_input('product_id'),vp3_input('plan_key'),vp3_input('name'),vp3_input('hosting_type'),vp3_input('billing_type'),max(0,(int)vp3_input('price_cents')),vp3_input('billing_interval'),max(1,(int)vp3_input('activation_limit')),max(0,(int)vp3_input('updates_months')),vp3_input('support_level'),vp3_input('status')];if($id){$values[]=$id;vp3_db()->prepare('UPDATE product_plans SET product_id=?,plan_key=?,name=?,hosting_type=?,billing_type=?,price_cents=?,billing_interval=?,activation_limit=?,updates_months=?,support_level=?,status=?,updated_at=NOW() WHERE id=?')->execute($values);}else{vp3_db()->prepare('INSERT INTO product_plans(product_id,plan_key,name,hosting_type,billing_type,price_cents,billing_interval,activation_limit,updates_months,support_level,status,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,NOW(),NOW())')->execute($values);$id=(int)vp3_db()->lastInsertId();}vp3_audit('admin',(int)$admin['id'],'plan.saved','product_plan',(string)$id);vp3_redirect('admin/plan.php?id='.$id);} $row=['product_id'=>0,'plan_key'=>'','name'=>'','hosting_type'=>'self_hosted','billing_type'=>'one_time','price_cents'=>0,'billing_interval'=>'none','activation_limit'=>1,'updates_months'=>12,'support_level'=>'standard','status'=>'draft'];if($id){$s=vp3_db()->prepare('SELECT * FROM product_plans WHERE id=?');$s->execute([$id]);$found=$s->fetch();if(!is_array($found)){http_response_code(404);exit('Plan not found.');}$row=$found;}$products=vp3_db()->query("SELECT id,name FROM products WHERE status<>'retired' ORDER BY name")->fetchAll();$pageTitle=$id?'Edit Plan':'New Plan';require VP3_ROOT.'/includes/admin-header.php';?><h1><?=$id?'Edit':'Create'?> plan</h1><form class="card" method="post"><?=vp3_csrf_field()?><div class="grid two"><div class="field"><label>Product</label><select name="product_id"><?php foreach($products as $p):?><option value="<?=(int)$p['id']?>" <?=$row['product_id']==$p['id']?'selected':''?>><?=vp3_e($p['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Plan key</label><input name="plan_key" value="<?=vp3_e($row['plan_key'])?>" pattern="[a-z0-9-]{3,100}" required></div><div class="field"><label>Name</label><input name="name" value="<?=vp3_e($row['name'])?>" required></div><div class="field"><label>Hosting type</label><select name="hosting_type"><?php foreach(['self_hosted','vp3_hosted','enterprise'] as $v):?><option <?=$row['hosting_type']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Billing type</label><select name="billing_type"><?php foreach(['one_time','subscription','custom'] as $v):?><option <?=$row['billing_type']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Billing interval</label><select name="billing_interval"><?php foreach(['none','monthly','yearly','custom'] as $v):?><option <?=$row['billing_interval']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Price cents</label><input name="price_cents" type="number" min="0" value="<?=(int)$row['price_cents']?>"></div><div class="field"><label>Activation limit</label><input name="activation_limit" type="number" min="1" value="<?=(int)$row['activation_limit']?>"></div><div class="field"><label>Updates months</label><input name="updates_months" type="number" min="0" value="<?=(int)$row['updates_months']?>"></div><div class="field"><label>Support level</label><input name="support_level" value="<?=vp3_e($row['support_level'])?>"></div><div class="field"><label>Status</label><select name="status"><?php foreach(['draft','active','retired'] as $v):?><option <?=$row['status']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div></div><button class="button">Save plan</button></form><?php require VP3_ROOT.'/includes/admin-footer.php';?>
